var base = getVar('api_base_url').replace(/\/$/, '');
var headers = {'Accept': 'application/json'};
try { var auth = getVar('api_auth_header'); if (auth) headers['Authorization'] = auth; } catch(e) {}
var url = base + args.path;
if (args.query) {
  var params = [];
  for (var k in args.query) params.push(encodeURIComponent(k) + '=' + encodeURIComponent(args.query[k]));
  if (params.length) url += '?' + params.join('&');
}
var resp = httpGet(url, headers);
return resp.body;

var base = getVar('api_base_url').replace(/\/$/, '');
var headers = {'Accept': 'application/json', 'Content-Type': 'application/json'};
try { var auth = getVar('api_auth_header'); if (auth) headers['Authorization'] = auth; } catch(e) {}
var resp = httpPost(base + args.path, JSON.stringify(args.body || {}), headers);
return resp.body;

